<template>
  <section>
    <div class="my-popups">
      <loader :is-visible="isLoading"></loader>

      <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
          <div class="modal-content">

            <!-- HEADER -->
            <div class="modal-header theme-primary partition-full d-flex">
              <h5 class="modal-title">{{ $t("Attachment") }}</h5>
              <button type="button" class="close" @click="Close">
                <em class="fa fa-times"></em>
              </button>
            </div>

            <!-- BODY -->
            <div class="modal-body">
              <dynamic-form ref="fileForm" :mandatorytext="MandatoryString" :schema="FormSchema" :buttons="buttons"
                @OnSubmit="uploadFile" />

              <AttachmentList ref="AttachmentList" :BillId="BillId" />
            </div>

          </div>
        </div>
      </div>
    </div>
  </section>
</template>


<script>
import DataService from "../../../services/DataService";
import AttachmentList from "./AttachmentList.vue";

export default {
  components: { AttachmentList },

  props: {
    BillId: { type: Number, required: true }
  },

  data() {
    return {
      isLoading: false,
      fileData: [],
      maxAttachmentSizeMB: 5,
      MandatoryString: this.$t("MandatoryString"),

      FormSchema: [
        {
          layoutType: "double",
          Data: [
            {
              astype: "TextField",
              label: this.$t("FileName"),
              name: "FileName",
              value: "",
              validationRules: { required: true, max: 2000 }
            },
            {
              astype: "FileField",
              label: this.$t("File"),
              name: "AttachItemImage",
              value: [],
              // will be filled after allowed types/size are loaded
              userGuide: "",
              validationRules: {
                required: true,
                validator: val => val && val.length > 0
              },
              config: {
                maxSize: 100,
                multiple: false,
                showAddIcon: false,
                accept: [], // 🔑 populated dynamically
                onChange: this.GetBase64String,
                onDeleteSelectedFiles: this.onDeleteSelectedFiles
              }
            }
          ]
        },
        {
          layoutType: "single",
          Data: [
            {
              astype: "TextAreaField",
              label: this.$t("Description"),
              name: "Description",
              value: "",
              config: { rows: 3 },
              validationRules: { required: false, max: 2000 }
            }
          ]
        }
      ],

      buttons: [
        {
          type: "submit",
          class: "btn btn-success",
          text: "<i class='fa fa-upload pr-2'></i>Upload"
        },
        {
          type: "button",
          class: "btn btn-danger",
          text: "<i class='fa fa-close pr-2'></i>Cancel",
          onClick: () => this.Close()
        }
      ],
      AllowedPerFileSizeInMb: 5,
      AllowedFileTypes: "pdf, doc, docx, xls, xlsx, txt"
    };
  },
  computed: {
    attachmentTooltip() {
      return `
      Maximum upload size per file: ${this.AllowedPerFileSizeInMb} MB
      Allowed File Types: ${this.AllowedFileTypes}
    `;
    }
  },
  async created() {
    await this.GetAllowFileType();
  },

  methods: {
    /* =========================
       CLOSE MODAL
    ========================= */
    Close() {
      this.$parent.FetchData();
      this.$parent.isAttachment = false;

    },

    /* =========================
       FILE DELETE
    ========================= */
    onDeleteSelectedFiles() {
      this.FormSchema[0].Data[1].value = [];
      this.fileData = [];
    },

    /* =========================
       FILE HANDLER
    ========================= */
    GetBase64String(evt) {
      const file = evt.target.files[0];
      if (!file) return;

      this.fileData = [];

      const reader = new FileReader();
      reader.onload = e => {
        const base64 = window.btoa(e.target.result);

        this.fileData.push({
          fileName: file.name,
          base64String: base64,
          fileSize: file.size,
          contentType: file.type,
          attachement_mime: JSON.stringify({
            ContentType: file.type,
            Size: file.size,
            Extension: file.name.split(".").pop()
          })
        });
        this.FormSchema[0].Data[1].value = [file];
      };
      reader.readAsBinaryString(file);
    },

    async GetAllowFileType() {
      try {
        var params = `moduleName=ClientBill`;
        const response = await DataService.AllowFileType(params);
        const rawTypes = response?.data?.AllowedFileTypes;
        const rawSize = response?.data?.AllowedPerFileSizeInMb;
        this.AllowedPerFileSizeInMb = rawSize || 5;
        this.AllowedFileTypes = rawTypes || "pdf, doc, docx, xls, xlsx, txt";
        if (!rawTypes) return;
        const types = rawTypes.split(",").map(t => t.trim().toLowerCase()).filter(Boolean);
        const fieldConfig = this.FormSchema[0].Data[1].config;
        fieldConfig.accept.splice(0);
        fieldConfig.acceptString = "";
        // fieldConfig.acceptString = types.map(t => `.${t}`).join(",");
        // types.forEach(type => {
        //   fieldConfig.accept.push({
        //     fileType: type.replace(".", ""),
        //     iconClass: this.getIconByFileType(type)
        //   });
        // });
        if (rawSize && !isNaN(rawSize)) {
          this.maxAttachmentSizeMB = parseInt(rawSize);
          debugger;
          setTimeout(() => {
            this.FormSchema[0].Data[1].config.maxSize = this.maxAttachmentSizeMB;
          }, 600);
        }

        // update tooltip text once allowed types/size are known
        this.FormSchema[0].Data[1].userGuide = this.attachmentTooltip;

      } catch (err) {
        console.error("GetAllowFileType failed", err);
      }
    },


    getIconByFileType(type) {
      const map = {
        pdf: "fa-file-pdf-o",
        doc: "fa-file-word-o",
        docx: "fa-file-word-o",
        xls: "fa-file-excel-o",
        xlsx: "fa-file-excel-o",
        xlsb: "fa-file-excel-o",
        txt: "fa-file-text-o",
        jpg: "fa-file-image-o",
        jpeg: "fa-file-image-o",
        png: "fa-file-image-o",
        msg: "fa-envelope-o"
      };
      return map[type.toLowerCase()] || "fa-file-o";
    },


    /* =========================
       UPLOAD
    ========================= */
    async uploadFile(data) {
      debugger
      // 🔒 FILE REQUIRED
      if (!this.fileData.length) {
        this.ShowAlert(this.$t("Attachment is required"), "warning");
        return;
      }

      // 🔒 FILE SIZE VALIDATION (FINAL GUARD)
      const maxMB = this.maxAttachmentSizeMB || 5;
      const maxBytes = maxMB * 1024 * 1024;

      const file = this.fileData[0];

      let extension = "";

      const allowedExtensions = ["pdf", "doc", "docx", "xls", "xlsx", "jpg", "jpeg", "png", "gif", "txt"];

      if (file.attachement_mime) {
        try {
          extension = JSON.parse(file.attachement_mime).Extension || "";
        } catch (e) {
          console.error("Invalid JSON", e);
        }
      }

      if (!allowedExtensions.includes(extension)) {

        this.ShowAlert("Invalid file type. Allowed: .pdf,.doc,.docx,.xls,.xlsx,.jpg,.jpeg,.png,.gif,.txt", 'failure', true, this.$t('Alert'));
        return;
      }

      if (file.fileSize > maxBytes) {
        this.ShowAlert(`File size should be less than ${maxMB} MB`, "warning"); return;
      }

      try {
        this.isLoading = true;

        const payload = {
          file_Name: data.FileName,
          file_Description: data.Description,
          invoice_id: this.BillId,
          attachment: JSON.stringify(this.fileData)
        };

        const formData = new FormData();
        formData.append("postString", JSON.stringify(payload));

        const response = await DataService.SaveBillAttachment(formData);

        this.isLoading = false;

        if (response.status === 200 && response.data.Status === "Success") {
          this.resetForm();
          this.$refs.AttachmentList.getBillAttachMentList();
          this.ShowAlert(this.$t("SaveBillAttachment"), "success");
        } else if (response.data.status === "Exceeds") {
          this.ShowAlert(this.$t("ExceedBillAttachmentLimit"), "warning");
        } else {
          this.ShowAlert(this.$t("UnknownError"), "failure");
        }
      } catch (err) {
        this.isLoading = false;
        console.error(err);
      }
    },


    /* =========================
       RESET
    ========================= */
    resetForm() {
      this.FormSchema[0].Data[0].value = "";
      this.FormSchema[0].Data[1].value = [];
      this.FormSchema[1].Data[0].value = "";
      this.fileData = [];
      document.querySelector(".crossimg a").click();
      this.$refs.fileForm.validateForm.reset();
    }
  }
};
</script>

<style></style>