<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full  d-flex">
                 <h4 class="modal-title">{{ EditData && EditData.RATE_SCHEDULE_ID ? $t('UpdateRate') : $t('addrate') }}</h4>
                    <span class="user-guide">
                            <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG"
                                role="button" aria-expanded="false" aria-controls="collapseExample"> <em
                                    class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                            <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                    <div class="con" v-html="$t('RateScheduleAdd')"></div>
                                </div>
                            </div>
                        </span>
                    <button type="button" class="close" v-on:click="CloseRateCode">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>
                <div class="modal-body">
                    <dynamic-form lang="en" ref="ResourceRate" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataService from "../../../services/DataService";

export default {
     props: {
        EditData: {
            type: Object,
            required: false,
            default: () => ({})
        },
         isBillingType: Boolean,
    },
    data() {
        return {
            isUtilitiesFetched: false,
            clientIdFromParent: null,
            isLoading: false,
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            companyId: null,
            userId: null,
            PageSize: 100,
            PageNumber: 1,
            searchCondition: '',
            GroupNewData: [],
            UtiltityNames: [],
            StateNames: [],
            WorkCodes: [],
            StatusData: [],
            clientList:[],
            isBillingType: false,
            isFetchingUtilities: false,
            isFetchingClients: false,
            hasInitialized: false,
            
            FormSchema: [{
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('ContractCompanyName'),
                            name: "ContractName",
                            value: "",
                            placeholder: "Select",
                            visibility: true,
                            isSearch: false,
                             validationRules: {
                                "required": true
                            },
                            config: {
                                options: [],
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                onChange: this.onSelectionChange
                            },      
                            disabled: true              
                        },
                     {
                            astype: "SearchableSelectField",
                            label: this.$t('UtilityName'),
                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                selectAll: true,
                                active: false,
                                inactive: false,
                                clear: true},
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": true
                            },
                            disabled: this.EditData.RATE_SCHEDULE_ID > 0 ? true: false
                        },
                    // {
                    //     astype: "SelectField",
                    //     label: this.$t('State'),
                    //     name: "State",
                    //     value: "",
                    //     placeholder: this.$t('Select State'),
                    //     visibility: true,
                    //     isSearch: false,
                    //     validationRules: {
                    //         "required": true
                    //     },
                    //     config: {
                    //         options: [],
                    //     },
                        
                    // },
                    {
                        astype: "SearchableSelectField",
                        label: this.$t('State'),
                        name: "State",
                        value: "",
                        placeholder: this.$t('Select State'),
                        visibility: true,
                        isSearch: false,
                        config: {
                            options: [],
                            actionButtons: {
                                selectAll: true,
                                active: false,
                                inactive: false,
                                clear: true
                            },
                            groupFields: [],
                            isMultiple: true,
                            minSearchLength: 0,
                            statusFieldConfig: {
                                fieldName: 'status',
                                activeValues: ['Active', 'active'],
                                inactiveValues: ['Inactive', 'inactive'],
                                activeColor: '#28a745',
                                inactiveColor: '#dc3545'
                            },
                        },
                        validationRules: {
                            "required": true
                        },
                        disabled:false
                    },
                                        
                    {
                        astype: "SelectField",
                        label: this.$t('WorkCode'),
                        name: "WorkCode",
                        value: "",
                        placeholder: this.$t('Select Work Code'),
                        validationRules: {
                            "required": true
                        },
                        config: {
                            options: [],
                        },
                        visibility: true
                    },
                    {
                        astype: "DateField",
                        label: this.$t('Start Date (M/D/YYYY)'),
                        name: "StartDate",
                        value: new Date(),
                        visibility: true,
                        placeholder: this.$t('StartDate'),
                        config: {
                            format: "MM/DD/YYYY"
                        },
                        validationRules: {
                            "required": true
                        }
                    },
                    {
                        astype: "DateField",
                        label: this.$t('End Date (M/D/YYYY)'),
                        name: "EndDate",
                        value: new Date(new Date().setFullYear(new Date().getFullYear() + 1)),
                        visibility: true,
                        placeholder: this.$t('EndDate'),
                        config: {
                            format: "MM/DD/YYYY"
                        },
                        validationRules: {
                            "required": true
                        },
                    },
                      {
                        astype: "NumericField",
                        label: this.$t('Rate'),
                        name: "Rate",
                        value: "",
                        placeholder: this.$t('Enter Rate'),
                         validationRules: { "required": true, max: 10 },
                        config: {
                            onkeypress: this.LimitRateDigits 
                        },
                        // visibility: true
                    },
                    {
                        astype: "SelectField",
                        label: this.$t('Status'),
                        name: "Status",
                        value: "",
                        placeholder: this.$t('Select Status'),
                        validationRules: {
                            //"required": false
                        },
                        config: {
                            options: [],
                        },
                        visibility: true
                    },
                    {
                        astype: "TextField",
                        label: this.$t('CustomerWorkCode'),
                        name: "CustomerWorkCode",
                        value: "",
                        placeholder: this.$t('Enter Customer Work Code'),
                        validationRules: {
                           // "required": false
                        },
                        config: {
                            options: [],
                        },
                        visibility: true
                    }
                    ]
                },
                {
                    layoutType: "single",
                    Data: [ {
                            astype: "TextAreaField",
                            label: this.$t('Comment'),
                            name: "COMMENT",
                            value: "",
                            placeholder: this.$t('Enter Comment'),
                            config: {
                                rows: 6,
                                maxlength: 500
                            },
                             validationRules: {
                        // "required": true,
                    },
                        }]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true,
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.CloseRateCode,
                }
            ]
        }
    },
    
       watch: {
        EditData: {
            immediate: true,
            deep: true,
            handler: function(newVal) {
                if (newVal && newVal.CLIENT_ID) {
                    this.clientIdFromParent = newVal.CLIENT_ID;
                    
                    if (this.FormSchema[0].Data[0]) {
                        this.FormSchema[0].Data[0].value = newVal.CLIENT_ID;
                        
                        if (newVal.RATE_SCHEDULE_ID && newVal.RATE_SCHEDULE_ID > 0) {
                            this.FormSchema[0].Data[1].disabled = true;
                        } else {
                            this.FormSchema[0].Data[1].disabled = false;
                        }
                        
                        if (this.$refs.ResourceRate) {
                            this.$refs.ResourceRate.UpdateKeyValue();
                        }
                    }
                }
            }
        }
    },
    
    async created() {
        const vm = this;

        vm.isBillingType = localStorage.getItem("billingType") === "USIC";

        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
          if (vm.FormSchema[0].Data[1]) {
            vm.FormSchema[0].Data[1].disabled = 
                (vm.EditData && vm.EditData.RATE_SCHEDULE_ID > 0);
        }

        await vm.loadStaticData();
        
        if (vm.EditData && vm.EditData.CLIENT_ID && !vm.hasInitialized) {
            vm.hasInitialized = true;
            await vm.loadClientSpecificData(vm.EditData.CLIENT_ID);
        }
    },
    
    async mounted() {
        const vm = this;
        
        if (vm.EditData && vm.EditData.CLIENT_ID && !vm.hasInitialized) {
            vm.hasInitialized = true;
            await vm.$nextTick();
            await vm.loadClientSpecificData(vm.EditData.CLIENT_ID);
        }
    },

    methods: {
LimitRateDigits: function(event) {
    debugger
    const input = event.target.value || '';
    
    if ([8, 9, 13, 27, 46, 37, 38, 39, 40].includes(event.keyCode)) {
        return;
    }
    
    if ((event.keyCode < 48 || event.keyCode > 57) && event.keyCode !== 190) {
        event.preventDefault();
        return;
    }
    
    const digitsCount = input.replace('.', '').length;
    if (digitsCount >= 10) {
        event.preventDefault();
    }
},        async loadStaticData() {
            const vm = this;
            vm.isLoading = true;
            
            try {
                await Promise.all([
                    vm.GetDDLCompanyContractClients(),
                    vm.GetStateListByCountryId(),
                    vm.GetWorkCodes(),
                    vm.GetStatusList()
                ]);
            } catch (error) {
                console.error('Error loading static data:', error);
            } finally {
                vm.isLoading = false;
            }
        },
        
        async loadClientSpecificData(clientId) {
            const vm = this;
            
            if (!clientId || vm.isUtilitiesFetched) {
                return;
            }
            
            if (vm.$refs.ResourceRate && vm.FormSchema[0].Data[0]) {
                vm.FormSchema[0].Data[0].value = clientId;
                vm.$refs.ResourceRate.UpdateKeyValue();
                
                await vm.$nextTick();
                
                await vm.fetchUtilitiesForClient(clientId);
                
                if (vm.EditData && vm.EditData.RATE_SCHEDULE_ID > 0) {
                    await vm.setEditModeValues();
                }
            }
        },
        
   async setEditModeValues() {
    const vm = this;
    vm.isLoading = true;
    
    try {
        if (vm.FormSchema[0].Data[1]) {
            vm.FormSchema[0].Data[1].disabled = true;
        }
        
        await new Promise(resolve => setTimeout(resolve, 300));
        
        // Set other field values
        vm.FormSchema[0].Data[1].value = vm.EditData.UTILITY_ID;
        
        // **FIX: Handle multiple states properly**
        if (vm.EditData.STATE_CODE) {
            let stateCodes = [];
            
            // Check if STATE_CODE is a string with commas
            if (typeof vm.EditData.STATE_CODE === 'string') {
                if (vm.EditData.STATE_CODE.includes(',')) {
                    // Comma-separated states
                    stateCodes = vm.EditData.STATE_CODE.split(',').map(s => s.trim());
                } else {
                    // Single state
                    stateCodes = [vm.EditData.STATE_CODE.trim()];
                }
            } 
            // Check if STATE_CODE is an array
            else if (Array.isArray(vm.EditData.STATE_CODE)) {
                stateCodes = vm.EditData.STATE_CODE.map(s => String(s).trim());
            }
            
            console.log("Setting state codes:", stateCodes);
            vm.FormSchema[0].Data[2].value = stateCodes;
        }
        
        vm.FormSchema[0].Data[3].value = vm.EditData.WORKCODE_ID?.toString();
        vm.FormSchema[0].Data[4].value = vm.EditData.START_DATE ? new Date(vm.EditData.START_DATE) : null;
        vm.FormSchema[0].Data[5].value = vm.EditData.END_DATE ? new Date(vm.EditData.END_DATE) : null;
        vm.FormSchema[0].Data[6].value = vm.EditData.AMOUNT;
        vm.FormSchema[0].Data[7].value = vm.EditData.STATUS_ID;
        vm.FormSchema[0].Data[8].value = vm.EditData.Billing_Code || "";
        vm.FormSchema[1].Data[0].value = vm.EditData.COMMENT;
        
        if (vm.$refs.ResourceRate) {
            vm.$refs.ResourceRate.UpdateKeyValue();
            
            // Force update after a small delay
            await vm.$nextTick();
            console.log("State field value after update:", 
                vm.$refs.ResourceRate.getPropertyValue("State", "value"));
        }
    } catch (error) {
        console.error('Error setting edit values:', error);
    } finally {
        vm.isLoading = false;
    }
},
        
        async fetchUtilitiesForClient(clientId) {
            const vm = this;
            
            if (!clientId || vm.isFetchingUtilities || vm.isUtilitiesFetched) {
                return;
            }
            
            vm.isFetchingUtilities = true;
            vm.isLoading = true;
            
            try {
                const url = `clientId=${clientId}&configId=&reqFrom=&clientIds=`;
                const response = await DataService.getUtilityList(url);
                
                if (response.data && response.data.length > 0) {
                    const SelectedUtilityList = response.data.map(item => ({
                        description: null,
                        displayValue: item.UTILITY_NAME,
                        groupText: null,
                        groupValue: null,
                        metaData: null,
                        text: item.UTILITY_NAME,
                        value: item.UTILITY_ID
                    }));
                    
                    if (vm.$refs.ResourceRate) {
                        vm.$refs.ResourceRate.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                        vm.$refs.ResourceRate.UpdateKeyValue();
                    }
                    
                    vm.isUtilitiesFetched = true;
                } else {
                    if (vm.$refs.ResourceRate) {
                        vm.$refs.ResourceRate.updateProperty("UtilityName", "config.options", []);
                        vm.$refs.ResourceRate.UpdateKeyValue();
                    }
                }
            } catch (error) {
                console.error('Error fetching utilities:', error);
                if (vm.$refs.ResourceRate) {
                    vm.$refs.ResourceRate.updateProperty("UtilityName", "config.options", []);
                    vm.$refs.ResourceRate.UpdateKeyValue();
                }
            } finally {
                vm.isLoading = false;
                vm.isFetchingUtilities = false;
            }
        },
        
        async onSelectionChange(value, clientId) {
            const vm = this;
            
            vm.isUtilitiesFetched = false;
            
            await vm.fetchUtilitiesForClient(clientId);
        },
        
        async GetDDLCompanyContractClients() {
            const vm = this;
            
            if (vm.isFetchingClients || vm.clientList.length > 0) {
                return;
            }
            
            vm.isFetchingClients = true;
            
            try {
                const url = `reqFrom=CUSTOM`;
                const response = await DataService.getClientList(url);
                
                if (response.data && response.data.items) {
                    vm.clientList = response.data.items;
                    
                    if (vm.$refs.ResourceRate) {
                        vm.$refs.ResourceRate.updateProperty("ContractName", "config.options", vm.clientList);
                        vm.$refs.ResourceRate.UpdateKeyValue();
                    }
                }
            } catch (error) {
                console.error('Error fetching client list:', error);
                vm.clientList = [];
            } finally {
                vm.isFetchingClients = false;
            }
        },
        
       GetStateListByCountryId() {
    debugger
    const vm = this;
    const url = `countryId=${223}&includeCandaState=true`;
    
    return new Promise((resolve) => {
        DataService.GetStateListByCountryId(url).then((response) => {
            if (response.data && response.data.result && response.data.result.length > 0) {
                vm.StateNames = response.data.result;
                
                const stateOptions = vm.StateNames.map(itm => ({
                    name: `${itm.STATE_NAME} (${itm.ISO_CODE_3})`,
                    text: `${itm.STATE_NAME} (${itm.ISO_CODE_3})`,  
                    value: itm.ISO_CODE_3,
                    status: 'Active',  
                    groupText: null,
                    groupValue: null,
                    metaData: null,
                    displayValue: `${itm.STATE_NAME} (${itm.ISO_CODE_3})`
                }));
                
                console.log("State options with status:", stateOptions);
                
                if (vm.$refs.ResourceRate) {
                    vm.$refs.ResourceRate.updateProperty("State", "config.options", stateOptions);
                    
                    if (vm.EditData && vm.EditData.STATE_CODE) {
                        const stateValue = Array.isArray(vm.EditData.STATE_CODE) 
                            ? vm.EditData.STATE_CODE 
                            : [vm.EditData.STATE_CODE];
                        vm.$refs.ResourceRate.updateProperty("State", "value", stateValue);
                        console.log("State value set to:", stateValue);
                    }
                    
                    // Force update
                    vm.$refs.ResourceRate.UpdateKeyValue();
                    
                    vm.$nextTick(() => {
                        console.log("After update - State field value:", 
                            vm.$refs.ResourceRate.getPropertyValue("State", "value"));
                    });
                }
            }
            resolve();
        }).catch(error => {
            console.error('Error fetching states:', error);
            resolve();
        });
    });
},
        
        GetWorkCodes() {
            const vm = this;
            
            return new Promise((resolve) => {
                DataService.GetWorkCodes().then((response) => {
                    if (response.data && response.data.result && response.data.result.length > 0) {
                        vm.WorkCodes = response.data.result;
                        vm.FormSchema[0].Data[3].config.options = vm.WorkCodes.map(itm => ({
                            name: itm.Text,
                            value: itm.Value
                        }));
                        
                        if (vm.$refs.ResourceRate) {
                            vm.$refs.ResourceRate.UpdateKeyValue();
                        }
                    }
                    resolve();
                }).catch(error => {
                    console.error('Error fetching work codes:', error);
                    resolve();
                });
            });
        },
        
       GetStatusList() {
    const vm = this;
    
    return new Promise((resolve) => {
        DataService.GetClientStatusList().then((response) => {
            try {
                const data = JSON.parse(response.data);
                if (data && Array.isArray(data)) {
                    const filteredStatus = data.filter(
                        itm => itm.STATUS_ID === 1001 || itm.STATUS_ID === 1002
                    );
                    
                    vm.FormSchema[0].Data[7].config.options = filteredStatus.map(itm => ({
                        name: itm.STATUS,
                        value: itm.STATUS_ID
                    }));
                    
                    // Default status to Active (1001) for new entries
                    if (!vm.EditData || !vm.EditData.RATE_SCHEDULE_ID || vm.EditData.RATE_SCHEDULE_ID === 0) {
                        vm.FormSchema[0].Data[7].value = 1001; // Active status
                    }
                    
                    if (vm.$refs.ResourceRate) {
                        vm.$refs.ResourceRate.UpdateKeyValue();
                    }
                }
            } catch (error) {
                console.error('Error parsing status data:', error);
            }
            resolve();
        }).catch(error => {
            console.error('Error fetching status list:', error);
            resolve();
        });
    });
},
     onSubmit(formfields, val) {
    debugger
    const vm = this;
    
    const result = vm.$refs.ResourceRate.validateForm.validate();
    if (!result) return;
    
    const startDate = new Date(formfields.StartDate);
    const endDate = new Date(formfields.EndDate);
    
    if (endDate < startDate) {
        vm.ShowAlert("Start Date should be less than End Date", 
            "warning", true, vm.$t("Alert"));
        return;
    }
    
    const isBillingType = vm.isBillingType === true;
    
    const formatDateForAPI = (date) => {
        if (!date) return null;
        
        const d = new Date(date);
        d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
        
        return d.toISOString().split('T')[0];
    };
    
    // Determine if this is insert or update
    const isUpdate = vm.EditData && vm.EditData.RATE_SCHEDULE_ID > 0;
    
    const objData = {
        RateScheduleId: isUpdate ? Number(vm.EditData.RATE_SCHEDULE_ID) : 0,
        ClientId: Number(formfields.ContractName),
        UtilityId: Array.isArray(formfields.UtilityName) ? 
            formfields.UtilityName.join(",") : String(formfields.UtilityName),
        WorkCodeId: Number(formfields.WorkCode),
        Rate: Number(formfields.Rate),
        StartDate: vm.$options.filters.formatDate(formfields.StartDate),
        EndDate: vm.$options.filters.formatDate(formfields.EndDate),
        State: String(formfields.State),
        Comment: formfields.Comment || "",
        Notes: formfields.Comment || "",
        StatusId: Number(formfields.Status ? formfields.Status : 1001),
                BCode: formfields.CustomerWorkCode ? 
                    String(formfields.CustomerWorkCode) : "",
        isBillingType: isBillingType
    };
    
    console.log("Is Update mode:", isUpdate);
    console.log("Sending to API:", objData);
    console.log("Original End Date from form:", formfields.EndDate);
    console.log("Formatted End Date:", formatDateForAPI(formfields.EndDate));
    
    vm.isLoading = true;
    
    DataService.AddUpdateRate(objData).then(response => {
        if (response.data != null) {
            console.log("Raw API Response:", response.data);
            
            try {
                const parsedResponse = JSON.parse(response.data);
                console.log("Parsed Response:", parsedResponse);
                
                // Check if response is array or object
                const Result = Array.isArray(parsedResponse) ? parsedResponse[0] : parsedResponse;
                console.log("Result object:", Result);
                
                // Debug: Print all keys in Result
                console.log("Keys in Result:", Object.keys(Result));
                console.log("RESULT property:", Result.RESULT);
                console.log("Result property:", Result.Result);
                console.log("Success property:", Result.Success);
                
                // Get the result code from whichever property exists
                let resultCode = null;
                let resultProperty = null;
                
                if (Result.RESULT !== undefined) {
                    resultCode = parseInt(Result.RESULT);
                    resultProperty = 'RESULT';
                } else if (Result.Result !== undefined) {
                    resultCode = parseInt(Result.Result);
                    resultProperty = 'Result';
                } else if (Result.Success !== undefined) {
                    resultCode = parseInt(Result.Success);
                    resultProperty = 'Success';
                }
                
                console.log(`Using ${resultProperty} property with value: ${resultCode}`);
                
                // Handle success cases (1 for both insert and update)
                if (resultCode === 1) {
                    // Check if this was insert or update based on RateScheduleId
                    if (isUpdate) {
                        vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('RateSchedule')]), 
                            "success", true, vm.$t("Alert"));
                    } else {
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('RateSchedule')]), 
                            "success", true, vm.$t("Alert"));
                    }
                    vm.CloseRateCode();
                } 
                // Handle error cases
                else if (resultCode === 0) {
                    // Overlap case for UPDATE (from stored procedure line 114)
                    const utilityOptions = vm.$refs.ResourceRate.schema[0].Data[1].config.options || [];
                    const utilityObj = utilityOptions.find(u => u.value == formfields.UtilityName);
                    const utilityName = utilityObj ? utilityObj.text : formfields.UtilityName;
                    
                    const startDate = vm.$options.filters.formatDate(formfields.StartDate);
                    const endDate = vm.$options.filters.formatDate(formfields.EndDate);
                    
                    const message = `"${utilityName}" Utility already exists from "${startDate}" to "${endDate}". Please select different date.`;
                    
                    vm.ShowAlert(message, "warning", true, vm.$t("Alert"));
                }
    else if (resultProperty === 'Result') {
    try {
        // Use the overlap information from Result.Result
        const overlapInfo = Result.Result || "";
        console.log("Overlap info from API:", overlapInfo);
        
        // Clean the text - remove <br> and extra spaces
        const cleanInfo = overlapInfo
            .replace(/<br>/gi, '')
            .replace(/\\/g, '')
            .trim();
        
        // The format is: "Utility Name,Start Date,End Date"
        const parts = cleanInfo.split(',');
        
        if (parts.length >= 3) {
            const existingUtilityName = parts[0].trim();
            const existingStartDate = parts[1].trim();
            const existingEndDate = parts[2].trim();
            
            // Show the actual overlapping schedule info
            const message = `"${existingUtilityName}" already has a rate schedule from ${existingStartDate} to ${existingEndDate}. Please select different dates.`;
            vm.ShowAlert(message, "warning", true, vm.$t("Alert"));
        } else {
            // Fallback if format is unexpected
            vm.ShowAlert("Selected date range overlaps with an existing schedule.", "warning", true, vm.$t("Alert"));
        }
    } catch (error) {
        console.error("Error parsing overlap info:", error);
        // Fallback message
        vm.ShowAlert("Date overlap detected with existing schedule.", "warning", true, vm.$t("Alert"));
    }
}
                else if (resultCode === 2) {
                    // Error case (from stored procedure line 169)
                    vm.ShowAlert(vm.$t("UnknownError"), "failure", true, vm.$t('Alert'));
                }
                else {
                    console.error("Unknown result code:", resultCode);
                    vm.ShowAlert(vm.$t("UnknownError"), "failure", true, vm.$t('Alert'));
                }
            } catch (error) {
                console.error('Error parsing response:', error);
                vm.ShowAlert(vm.$t("UnknownError"), "failure", true, vm.$t('Alert'));
            }
        }
    }).catch(error => {
        console.error('Submit error:', error);
        vm.ShowAlert(vm.$t("UnknownError"), "failure", true, vm.$t('Alert'));
    }).finally(() => {
        vm.isLoading = false;
    });
},
        
        CloseRateCode() {
            if (this.isBillingType) {
                this.$parent.FetchData(); 
                this.$parent.IsAddRate = false;
            }
        }
    }
}
</script>